@click.group(cls=FRR_AbbreviationGroup, name='metric-style',)
def frr_config_router_isis_metricstyle(metricstyle_='metric-style'):
    """Use old-style (ISO 10589) or new-style packet formats"""
    global COMMON_DATA_MAP
    #ctx = click.get_current_context()
    #config_db = ValidatedConfigDBConnector(db.cfgdb)
    
    data_gen = {}
    name = frr_config_router_isis_metricstyle.name
    
    if 'ISIS_NODE|metric-style' not in COMMON_DATA_MAP:
        COMMON_DATA_MAP['ISIS_NODE|metric-style'] = {}

    for key, val in data_gen.items():
        if key.islower() and key in COMMON_DATA_MAP['ISIS_NODE|metric-style']:
            key = key.upper()
        COMMON_DATA_MAP['ISIS_NODE|metric-style'][key] = val
    
    #######################
    key_store = []
    global PREFIX_TMP
    for k, v in COMMON_DATA_MAP['ISIS_NODE|metric-style'].items():
        if k.islower() and k != v:
            key_store.append(k)
        if k != v or '_NODE' not in v:
            key_store.append(v)
    key_store.insert(0, 'metric-style')
    previous_key = key_store[:-1]
    if PREFIX_TMP and 'ISIS_NODE' not in BASE_NODE:
        pre_key = PREFIX_TMP.split('|')[-1]
        if key_store[0].startswith(pre_key):
            if '|' not in PREFIX_TMP:
                PREFIX_TMP = PREFIX_TMP.replace(f'{pre_key}', '')
            else:
                PREFIX_TMP = PREFIX_TMP.replace(f'|{pre_key}', '')
        if PREFIX_TMP != '' and key_store[0] not in PREFIX_TMP:
            key_store[0] = f'{PREFIX_TMP}|{key_store[0]}'
            if len(previous_key) == 0:
                previous_key = [PREFIX_TMP]
            else:
                previous_key[0] = f'{PREFIX_TMP}|{previous_key[0]}'
        if PREFIX_TMP.endswith(f'|{key_store[0]}'):
            key_store[0] = PREFIX_TMP
    
    COMMON_DATA_MAP['ISIS_NODE'] = tuple(key_store)
    PREFIX_TMP = '|'.join(key_store)

    pass


